import { Component, computed, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { RouterLink } from '@angular/router';
import { CentsPipe } from '../../shared/cents.pipe';
import { DelinquencyRow } from '../../core/models';

@Component({
  selector: 'app-delinquency',
  standalone: true,
  imports: [CommonModule, RouterLink, CentsPipe],
  templateUrl: './delinquency.component.html',
  styleUrl: './delinquency.component.css',
})
export class DelinquencyComponent {
  readonly loading = signal(false);
  readonly error = signal('');

  /** Leases with an outstanding, past-due balance — only Casey (Unit 201). */
  readonly rows = signal<DelinquencyRow[]>([
    {
      lease: {
        id: 'l3',
        unitId: 'u3',
        tenantId: 't3',
        startsOn: '2026-01-01',
        endsOn: '2026-12-31',
        rentCents: 190000,
        dueDay: 1,
        status: 'delinquent',
      },
      tenant: { id: 't3', name: 'Casey Morgan', email: 'tenant3@demo', role: 'tenant' },
      unit: { id: 'u3', number: '201', bedrooms: 2, rentCents: 190000 },
      balanceCents: 240000,
      daysPastDue: 42,
    },
  ]);

  /** Count of delinquent leases. */
  readonly delinquentCount = computed<number>(() => this.rows().length);

  /** Sum of all outstanding balances. */
  readonly totalOverdueCents = computed<number>(() =>
    this.rows().reduce((sum, r) => sum + r.balanceCents, 0),
  );
}
